    let command = shell_function_payload_command(&invocation.payload)?;
    Some(PostToolUsePayload {
        tool_name: HookToolName::bash(),
        tool_use_id: invocation.call_id.clone(),
        tool_input: serde_json::json!({ "command": command }),
        tool_response,
    })
}

